import{_ as s,c as a,o as n,ae as t}from"./chunks/framework.uY-EIwh2.js";const y=JSON.parse('{"title":"Advanced Query Setup","description":"","frontmatter":{},"headers":[],"relativePath":"rest/advanced.md","filePath":"rest/advanced.md"}'),r={name:"rest/advanced.md"};function l(o,e,p,i,c,d){return n(),a("div",null,e[0]||(e[0]=[t(`<h1 id="advanced-query-setup" tabindex="-1">Advanced Query Setup <a class="header-anchor" href="#advanced-query-setup" aria-label="Permalink to &quot;Advanced Query Setup&quot;">​</a></h1><h2 id="customizing-polly" tabindex="-1">Customizing Polly <a class="header-anchor" href="#customizing-polly" aria-label="Permalink to &quot;Customizing Polly&quot;">​</a></h2><p>It was mentioned in <a href="./">Getting Started</a> that <a href="https://github.com/App-vNext/Polly#wait-and-retry" target="_blank" rel="noreferrer">wait-and-retry</a> Polly policy is configured by default. This waits a certain amount of time after a failed query and then re-attempts it. The number of times the query is retried can be configured when registering the Census REST services:</p><div class="language-csharp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#E5C07B;">services</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">AddCensusRestServices</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">maxRetryAttempts</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">5</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="using-alternative-census-implementations" tabindex="-1">Using Alternative Census Implementations <a class="header-anchor" href="#using-alternative-census-implementations" aria-label="Permalink to &quot;Using Alternative Census Implementations&quot;">​</a></h2><p>With Census being, at one point in its history, two years out of date on any static data, the API developer community began to extract and share information through alternative means. Some of these efforts have included Census-like API implementations. We&#39;ll be using <a href="https://github.com/PS2Sanctuary/Sanctuary.Census" target="_blank" rel="noreferrer">Sanctuary.Census</a> as one such example.</p><p><code>DbgCensus</code> can be easily configured to use alternative Census implementations, provided their interface is similar. The <a href="https://github.com/carlst99/DbgCensus/tree/main/Samples/RestSample" target="_blank" rel="noreferrer">REST Sample</a> demonstrates the following instruction by means of configuring a <em>named options</em> instance, so that the configured third-party Census options can be injected anywhere.</p><ol><li><p>Create a <code>CensusQueryOptions</code> instance, and point it towards the alternative Census implementation:</p><div class="language-csharp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#E5C07B;">CensusQueryOptions</span><span style="color:#E06C75;"> sanctuaryQueryOptions</span><span style="color:#56B6C2;"> =</span><span style="color:#ABB2BF;"> new()</span></span>
<span class="line"><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#E06C75;">    RootEndpoint</span><span style="color:#56B6C2;"> =</span><span style="color:#98C379;"> &quot;https://census.lithafalcon.cc&quot;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p>Then, simply pass in these options when creating a query builder.</p><div class="language-csharp line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#E5C07B;">QueryBuilder</span><span style="color:#E06C75;"> builder</span><span style="color:#56B6C2;"> =</span><span style="color:#ABB2BF;"> new(</span><span style="color:#E06C75;">sanctuaryQueryOptions</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// OR</span></span>
<span class="line"><span style="color:#E5C07B;">IQueryBuilder</span><span style="color:#E06C75;"> builder</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> _queryService</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">CreateQuery</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">sanctuaryQueryOptions</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li></ol>`,8)]))}const m=s(r,[["render",l]]);export{y as __pageData,m as default};
